script.text:
      &ScriptQueryData;

function active$FormDepartment(f) {f.add_onResponseComplete(on$FormDepartment$ResponseComplete);&ActiveForm;}
function close$FormDepartment(f) {try {f.remove_onResponseComplete(on$FormDepartment$ResponseComplete)} catch (ex) {};&CloseForm;}
function on$FormDepartment$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      objectBehavior$Dir$Irregular.checkCode(f, 'ma_bp');
      break;
    default:
      break;
  }
}

      &TabChanged;
      &ScriptIrregular;
